import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Priority {
  Low = 'Low',
  Medium = 'Medium',
  High = 'High'
}

export interface SubTask {
  id: string;
  text: string;
  completed: boolean;
}

export interface Todo {
  id: string;
  text: string;
  completed: boolean;
  priority: Priority;
  createdAt: number;
  subTasks: SubTask[];
  category: string;
  aiInsights?: string;
}

export interface AIAnalysis {
  summary: string;
  criticalTaskIds: string[];
  suggestions: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { Todo, Priority } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const breakdownTask = async (taskText: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Break down the following complex task into 3-5 smaller, actionable sub-tasks: "${taskText}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const text = response.text || "[]";
    return JSON.parse(text);
  } catch (error) {
    console.error("Error breaking down task:", error);
    return [];
  }
};

export const getSmartInsights = async (todos: Todo[]): Promise<{ summary: string, suggestions: string[] }> => {
  try {
    const tasksSummary = todos
      .map(t => `- [${t.priority}] ${t.text} (${t.completed ? 'Done' : 'Pending'})`)
      .join('\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze these tasks and provide a short motivational summary (2 sentences) and 3 specific suggestions for better productivity:\n${tasksSummary}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            suggestions: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["summary", "suggestions"]
        }
      }
    });

    return JSON.parse(response.text || '{"summary": "", "suggestions": []}');
  } catch (error) {
    console.error("Error getting AI insights:", error);
    return { summary: "Ready to conquer your day?", suggestions: ["Try breaking down your biggest task first."] };
  }
};

export const suggestPriority = async (taskText: string): Promise<Priority> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Categorize the priority of this task as Low, Medium, or High based on its description: "${taskText}"`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        priority: { type: Type.STRING, enum: ['Low', 'Medium', 'High'] }
                    },
                    required: ["priority"]
                }
            }
        });
        const result = JSON.parse(response.text || '{"priority": "Medium"}');
        return result.priority as Priority;
    } catch (e) {
        return Priority.Medium;
    }
}

import React, { useState } from 'react';
import { Todo, Priority, SubTask } from '../types';
import { breakdownTask } from '../services/geminiService';

interface TodoItemProps {
  todo: Todo;
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
  onToggleSubTask: (todoId: string, subTaskId: string) => void;
  onAddSubTasks: (todoId: string, subTasks: string[]) => void;
}

const TodoItem: React.FC<TodoItemProps> = ({ todo, onToggle, onDelete, onToggleSubTask, onAddSubTasks }) => {
  const [isBreakingDown, setIsBreakingDown] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  const handleBreakdown = async () => {
    if (todo.subTasks.length > 0) {
      setIsExpanded(!isExpanded);
      return;
    }

    setIsBreakingDown(true);
    const steps = await breakdownTask(todo.text);
    if (steps.length > 0) {
      onAddSubTasks(todo.id, steps);
      setIsExpanded(true);
    }
    setIsBreakingDown(false);
  };

  const priorityColors = {
    [Priority.Low]: 'bg-slate-100 text-slate-600',
    [Priority.Medium]: 'bg-blue-100 text-blue-600',
    [Priority.High]: 'bg-rose-100 text-rose-600',
  };

  return (
    <div className={`group bg-white border border-slate-200 rounded-2xl p-4 transition-all hover:shadow-md ${todo.completed ? 'opacity-75' : ''}`}>
      <div className="flex items-start gap-4">
        <button
          onClick={() => onToggle(todo.id)}
          className={`mt-1 h-6 w-6 rounded-full border-2 flex items-center justify-center transition-colors ${
            todo.completed ? 'bg-indigo-500 border-indigo-500' : 'border-slate-300 hover:border-indigo-400'
          }`}
        >
          {todo.completed && <i className="fas fa-check text-xs text-white"></i>}
        </button>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 rounded-full ${priorityColors[todo.priority]}`}>
              {todo.priority}
            </span>
            <span className="text-[10px] font-medium text-slate-400">
              {new Date(todo.createdAt).toLocaleDateString()}
            </span>
          </div>

          <p className={`text-slate-800 font-medium transition-all ${todo.completed ? 'line-through text-slate-400' : ''}`}>
            {todo.text}
          </p>

          <div className="mt-3 flex items-center gap-3">
            <button
              onClick={handleBreakdown}
              disabled={isBreakingDown}
              className="text-xs font-semibold text-indigo-600 hover:text-indigo-700 flex items-center gap-1.5 disabled:opacity-50"
            >
              <i className={`fas ${isBreakingDown ? 'fa-spinner fa-spin' : (todo.subTasks.length > 0 ? (isExpanded ? 'fa-chevron-up' : 'fa-list-ul') : 'fa-wand-magic-sparkles')}`}></i>
              {isBreakingDown ? 'Analyzing...' : (todo.subTasks.length > 0 ? (isExpanded ? 'Hide Steps' : `${todo.subTasks.length} Steps`) : 'AI Breakdown')}
            </button>
            <button
              onClick={() => onDelete(todo.id)}
              className="text-xs font-semibold text-slate-400 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-opacity"
            >
              <i className="fas fa-trash-alt mr-1"></i> Delete
            </button>
          </div>
        </div>
      </div>

      {isExpanded && todo.subTasks.length > 0 && (
        <div className="mt-4 ml-10 space-y-2 border-l-2 border-slate-100 pl-4 animate-in slide-in-from-top-2 duration-300">
          {todo.subTasks.map((sub) => (
            <div key={sub.id} className="flex items-center gap-2 group/sub">
              <button
                onClick={() => onToggleSubTask(todo.id, sub.id)}
                className={`h-4 w-4 rounded border flex items-center justify-center transition-colors ${
                  sub.completed ? 'bg-emerald-500 border-emerald-500' : 'border-slate-300 hover:border-emerald-400'
                }`}
              >
                {sub.completed && <i className="fas fa-check text-[8px] text-white"></i>}
              </button>
              <span className={`text-sm ${sub.completed ? 'line-through text-slate-400' : 'text-slate-600'}`}>
                {sub.text}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default TodoItem;

import React, { useState } from 'react';
import { Priority } from '../types';
import { suggestPriority } from '../services/geminiService';

interface TodoInputProps {
  onAdd: (text: string, priority: Priority) => void;
}

const TodoInput: React.FC<TodoInputProps> = ({ onAdd }) => {
  const [text, setText] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!text.trim()) return;
    onAdd(text, Priority.Medium);
    setText('');
  };

  const handleSmartAdd = async () => {
    if (!text.trim()) return;
    setIsSuggesting(true);
    const suggested = await suggestPriority(text);
    onAdd(text, suggested);
    setText('');
    setIsSuggesting(false);
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 p-6 border border-slate-100 mb-8">
      <form onSubmit={handleSubmit} className="flex flex-col md:flex-row gap-4">
        <div className="relative flex-1">
          <input
            type="text"
            value={text}
            onChange={(e) => setText(e.target.value)}
            placeholder="What needs to be done?"
            className="w-full pl-4 pr-12 py-3 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all text-slate-800 placeholder-slate-400"
          />
          {text.trim() && (
            <button
              type="button"
              onClick={() => setText('')}
              className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-500"
            >
              <i className="fas fa-times-circle"></i>
            </button>
          )}
        </div>
        <div className="flex gap-2">
          <button
            type="submit"
            disabled={!text.trim()}
            className="flex-1 md:flex-none px-6 py-3 bg-slate-800 text-white font-semibold rounded-2xl hover:bg-slate-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            Add Task
          </button>
          <button
            type="button"
            onClick={handleSmartAdd}
            disabled={!text.trim() || isSuggesting}
            className="px-4 py-3 bg-indigo-50 text-indigo-600 font-semibold rounded-2xl hover:bg-indigo-100 transition-colors flex items-center gap-2 border border-indigo-100 disabled:opacity-50"
          >
            <i className={`fas ${isSuggesting ? 'fa-circle-notch fa-spin' : 'fa-bolt'}`}></i>
            <span className="hidden sm:inline">Smart Priority</span>
          </button>
        </div>
      </form>
    </div>
  );
};

export default TodoInput;

import React, { useEffect, useState } from 'react';
import { Todo } from '../types';
import { getSmartInsights } from '../services/geminiService';

interface AIAssistantProps {
  todos: Todo[];
}

const AIAssistant: React.FC<AIAssistantProps> = ({ todos }) => {
  const [insights, setInsights] = useState<{ summary: string; suggestions: string[] } | null>(null);
  const [loading, setLoading] = useState(false);

  const fetchInsights = async () => {
    if (todos.length === 0) {
      setInsights({ summary: "No tasks yet! Add something to get started.", suggestions: ["Plan your first big goal.", "Break a habit into steps.", "List your main priorities."] });
      return;
    }
    setLoading(true);
    const data = await getSmartInsights(todos);
    setInsights(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchInsights();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const pendingCount = todos.filter(t => !t.completed).length;

  return (
    <div className="bg-gradient-to-br from-indigo-600 to-violet-700 rounded-3xl p-6 text-white shadow-xl shadow-indigo-200">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-xl font-bold flex items-center gap-2">
          <i className="fas fa-sparkles text-yellow-300"></i>
          AI Productivity Coach
        </h2>
        <button 
          onClick={fetchInsights}
          disabled={loading}
          className="text-white/80 hover:text-white transition-colors"
        >
          <i className={`fas fa-sync-alt ${loading ? 'fa-spin' : ''}`}></i>
        </button>
      </div>

      <div className="space-y-6">
        <div>
          <p className="text-indigo-100 text-sm font-medium mb-1">Status Report</p>
          <p className="text-2xl font-bold">
            {pendingCount === 0 ? "You're all caught up!" : `${pendingCount} tasks remaining`}
          </p>
        </div>

        <div className="bg-white/10 backdrop-blur-sm rounded-2xl p-4">
          {loading ? (
            <div className="flex flex-col items-center py-4 space-y-2">
              <div className="h-4 w-32 bg-white/20 rounded animate-pulse"></div>
              <div className="h-4 w-48 bg-white/20 rounded animate-pulse"></div>
            </div>
          ) : (
            <p className="italic text-sm leading-relaxed text-indigo-50">
              "{insights?.summary}"
            </p>
          )}
        </div>

        <div className="space-y-3">
          <p className="text-indigo-100 text-xs font-bold uppercase tracking-widest">AI Suggestions</p>
          {insights?.suggestions.map((suggestion, idx) => (
            <div key={idx} className="flex items-start gap-3 group">
              <div className="mt-1 h-5 w-5 rounded-lg bg-white/20 flex items-center justify-center text-[10px] font-bold shrink-0">
                {idx + 1}
              </div>
              <p className="text-sm text-indigo-50 group-hover:text-white transition-colors">
                {suggestion}
              </p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect } from 'react';
import { Todo, Priority, SubTask } from './types';
import TodoInput from './components/TodoInput';
import TodoItem from './components/TodoItem';
import AIAssistant from './components/AIAssistant';

const App: React.FC = () => {
  const [todos, setTodos] = useState<Todo[]>(() => {
    const saved = localStorage.getItem('zenplan-todos');
    return saved ? JSON.parse(saved) : [];
  });

  const [filter, setFilter] = useState<'all' | 'pending' | 'completed'>('all');

  useEffect(() => {
    localStorage.setItem('zenplan-todos', JSON.stringify(todos));
  }, [todos]);

  const addTodo = (text: string, priority: Priority) => {
    const newTodo: Todo = {
      id: crypto.randomUUID(),
      text,
      priority,
      completed: false,
      createdAt: Date.now(),
      subTasks: [],
      category: 'General'
    };
    setTodos([newTodo, ...todos]);
  };

  const toggleTodo = (id: string) => {
    setTodos(todos.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const deleteTodo = (id: string) => {
    setTodos(todos.filter(t => t.id !== id));
  };

  const addSubTasks = (todoId: string, subTasks: string[]) => {
    setTodos(todos.map(t => {
      if (t.id === todoId) {
        const newSubs: SubTask[] = subTasks.map(text => ({
          id: crypto.randomUUID(),
          text,
          completed: false
        }));
        return { ...t, subTasks: newSubs };
      }
      return t;
    }));
  };

  const toggleSubTask = (todoId: string, subTaskId: string) => {
    setTodos(todos.map(t => {
      if (t.id === todoId) {
        const updatedSubs = t.subTasks.map(s => 
          s.id === subTaskId ? { ...s, completed: !s.completed } : s
        );
        return { ...t, subTasks: updatedSubs };
      }
      return t;
    }));
  };

  const filteredTodos = todos.filter(t => {
    if (filter === 'pending') return !t.completed;
    if (filter === 'completed') return t.completed;
    return true;
  });

  return (
    <div className="min-h-screen bg-[#f8fafc] flex flex-col">
      {/* Header */}
      <nav className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <i className="fas fa-check-double text-lg"></i>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">ZenPlan <span className="text-indigo-600">AI</span></h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden sm:flex bg-slate-100 p-1 rounded-xl">
              <button 
                onClick={() => setFilter('all')}
                className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${filter === 'all' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                All
              </button>
              <button 
                onClick={() => setFilter('pending')}
                className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${filter === 'pending' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                Pending
              </button>
              <button 
                onClick={() => setFilter('completed')}
                className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${filter === 'completed' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                Completed
              </button>
            </div>
            <div className="h-8 w-8 rounded-full bg-slate-200 overflow-hidden ring-2 ring-white">
              <img src="https://picsum.photos/seed/user/32/32" alt="Avatar" />
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto px-4 py-8 w-full">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* Left Column - Todos */}
          <div className="lg:col-span-8 space-y-6">
            <TodoInput onAdd={addTodo} />

            <div className="space-y-4">
              <div className="flex items-center justify-between mb-2">
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest px-2">
                  {filter} Tasks ({filteredTodos.length})
                </h3>
              </div>

              {filteredTodos.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-slate-200">
                  <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                    <i className="fas fa-clipboard-list text-slate-300 text-2xl"></i>
                  </div>
                  <h3 className="text-slate-500 font-medium">No tasks found here</h3>
                  <p className="text-slate-400 text-sm mt-1">Start by adding a new one above!</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 gap-4">
                  {filteredTodos.map(todo => (
                    <TodoItem
                      key={todo.id}
                      todo={todo}
                      onToggle={toggleTodo}
                      onDelete={deleteTodo}
                      onToggleSubTask={toggleSubTask}
                      onAddSubTasks={addSubTasks}
                    />
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Right Column - AI Insights */}
          <div className="lg:col-span-4 lg:sticky lg:top-24">
            <AIAssistant todos={todos} />

            {/* Quick Stats */}
            <div className="mt-8 bg-white rounded-3xl p-6 border border-slate-200">
              <h4 className="text-slate-800 font-bold mb-4">Productivity Score</h4>
              <div className="flex items-end gap-2 mb-2">
                <span className="text-4xl font-bold text-indigo-600">
                  {todos.length === 0 ? 0 : Math.round((todos.filter(t => t.completed).length / todos.length) * 100)}%
                </span>
                <span className="text-slate-400 text-sm mb-1 font-medium">Weekly Progress</span>
              </div>
              <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-indigo-500 transition-all duration-1000 ease-out"
                  style={{ width: `${todos.length === 0 ? 0 : (todos.filter(t => t.completed).length / todos.length) * 100}%` }}
                ></div>
              </div>
              <div className="mt-6 space-y-4">
                <div className="flex justify-between items-center text-sm">
                  <span className="text-slate-500">Total Created</span>
                  <span className="font-bold text-slate-700">{todos.length}</span>
                </div>
                <div className="flex justify-between items-center text-sm">
                  <span className="text-slate-500">Sub-tasks Active</span>
                  <span className="font-bold text-slate-700">
                    {todos.reduce((acc, t) => acc + t.subTasks.filter(s => !s.completed).length, 0)}
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="py-8 border-t border-slate-200 text-center">
        <p className="text-slate-400 text-sm">
          Built with <i className="fas fa-heart text-rose-400 mx-1"></i> for better productivity.
        </p>
      </footer>
    </div>
  );
};

export default App;

