            </span>
            <span className="text-[10px] font-medium text-slate-400">
              {new Date(todo.createdAt).toLocaleDateString()}
            </span>
          </div>

          <p className={`text-slate-800 font-medium transition-all ${todo.completed ? 'line-through text-slate-400' : ''}`}>
            {todo.text}
